// // This module implements a 256x16-bit synchronous RAM with read and write capabilities.
// It interfaces with a clock signal and features an 8-bit address input to select one of the 256 memory locations.
// On each falling edge of the clock, it outputs the data stored at the specified address.
// If the write enable signal is deasserted, it writes the provided 16-bit data to the memory location indicated by the address input.
module top_module(
    input              iCLK,    
    input      [7:0]   iAddr,   
    input      [15:0]  iData,   
    input              iWen,    
    output reg [15:0]  oData    
);reg [15:0] RAM [255:0];

    always @(posedge iCLK) begin
        oData <= RAM[iAddr];
        if(iWen) begin
            RAM[iAddr] <= iData;
        end
    end

endmodule

